const fmt = (n) => {
  if (n == null || isNaN(n)) return "S/ 0.00";
  const neg = n < 0;
  const abs = Math.abs(n);
  const s = abs.toLocaleString("es-PE",{minimumFractionDigits:2,maximumFractionDigits:2});
  return neg ? `(S/ ${s})` : `S/ ${s}`;
};
const fmtShort = (n) => {
  if (n==null||isNaN(n)) return "0";
  if (Math.abs(n)>=1e6) return (n/1e6).toFixed(1)+"M";
  if (Math.abs(n)>=1e3) return (n/1e3).toFixed(1)+"K";
  return n.toFixed(0);
};
const metodoLabel = (m) => m==="LR"?"Línea Recta (V.R.)":m==="L"?"Línea Recta":m==="S"?"Sin Depreciación":m||"N/A";

